## try/catch: capturar errores

Cuando algo falla en JavaScript — una división inválida, un valor `undefined`, una petición que no llega — el programa lanza un **error** y se detiene. `try/catch` permite **capturar ese error** y decidir qué hacer en lugar de que todo explote.

### Estructura básica

```js
try {
  // código que puede fallar
  const resultado = operacionRiesgosa();
  console.log(resultado);
} catch (error) {
  // se ejecuta SOLO si hubo un error
  console.error('Algo salió mal:', error.message);
}
```

Si el código dentro de `try` lanza un error, JavaScript salta inmediatamente al bloque `catch`. Si no hay error, `catch` se ignora por completo.

### El objeto `error`

El `catch` recibe un objeto con información del error:

```js
try {
  null.propiedad; // TypeError
} catch (error) {
  console.log(error.name);    // 'TypeError'
  console.log(error.message); // "Cannot read properties of null"
  console.log(error.stack);   // traza de la pila de llamadas
}
```

### `finally`: siempre se ejecuta

```js
try {
  const datos = JSON.parse(textoInvalido);
} catch (error) {
  console.error('JSON inválido');
} finally {
  console.log('Esto se ejecuta siempre, haya error o no');
  // útil para cerrar conexiones, liberar recursos, etc.
}
```

### Lanzar errores propios con `throw`

```js
function dividir(a, b) {
  if (b === 0) throw new Error('No se puede dividir por cero');
  return a / b;
}
```

examples.code:
// Sin try/catch: el programa se detiene
// JSON.parse('texto inválido'); // ← SyntaxError: rompe todo

// Con try/catch: el error queda controlado
try {
  const datos = JSON.parse('esto no es json');
  console.log(datos);
} catch (error) {
  console.log('Error capturado:', error.name); // SyntaxError
  console.log('Mensaje:', error.message);
}
console.log('El programa continúa...');

function obtenerEdad(usuario) {
  if (!usuario) throw new Error('Usuario requerido');
  if (typeof usuario.edad !== 'number') throw new TypeError('La edad debe ser un número');
  if (usuario.edad < 0) throw new RangeError('La edad no puede ser negativa');
  return usuario.edad;
}

try {
  console.log(obtenerEdad(null));         // Error: Usuario requerido
} catch (e) { console.error(e.message); }

try {
  console.log(obtenerEdad({ edad: -5 })); // RangeError
} catch (e) { console.error(e.message); }

async function cargarDatos(url) {
  try {
    const res = await fetch(url);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return await res.json();
  } catch (error) {
    console.error('No se pudieron cargar los datos:', error.message);
    return null; // valor seguro para continuar
  } finally {
    console.log('Intento de carga finalizado');
  }
}

exercises.starterCode:
let mensajeError;

try {
  JSON.parse('no es json');
} catch (error) {
  mensajeError = error.message;
}

function validarEdad(edad) {
  if (edad === null || edad === undefined) throw new Error('Edad requerida');
  if (edad < 0 || edad > 120) throw new RangeError('Edad inválida');
  return edad;
}

function parsearSeguro(texto) {
  try {
    return JSON.parse(texto);
  } catch {
    return null;
  }
}
